from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a celestial body (or person) into a single,
    fluent sentence.  The function tries to use a natural phrasing for each
    predicate and joins the resulting clauses with commas and a final “and”.
    """
    if not triples:
        return ""

    # Group triples by subject for better sentence construction
    subject_triples: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Simple template mapping for common predicates
    def phrase(t: Triple) -> str:
        subj, pred, obj = t.subject, t.predicate, t.object

        # Normalise predicate strings (remove spaces, lower‑case)
        p = pred.strip().lower()

        # Mapping of predicate to a readable clause
        if p == "discoverer":
            return f"{subj} was discovered by {obj}"
        if p == "discovered":
            return f"{subj} was discovered on {obj}"
        if p == "epoch":
            return f"{subj} has epoch {obj}"
        if p == "apoapsis":
            return f"{subj} has an apoapsis of {obj}"
        if p == "periapsis":
            return f"{subj} has a periapsis of {obj}"
        if p == "orbitalperiod":
            return f"{subj} has an orbital period of {obj}"
        if p == "averagespeed":
            return f"{subj} travels at an average speed of {obj}"
        if p == "escapevelocity":
            return f"{subj} has an escape velocity of {obj}"
        if p == "mass":
            return f"{subj} has a mass of {obj}"
        if p == "density":
            return f"{subj} has a density of {obj}"
        if p == "temperature":
            return f"{subj} has a temperature of {obj}"
        if p == "maximumtemperature":
            return f"{subj} has a maximum temperature of {obj}"
        if p == "meantemperature":
            return f"{subj} has a mean temperature of {obj}"
        if p == "minimumtemperature":
            return f"{subj} has a minimum temperature of {obj}"
        if p == "rotationperiod":
            return f"{subj} has a rotation period of {obj}"
        if p == "surfacearea":
            return f"{subj} has a surface area of {obj}"
        if p == "absolutemagnitude":
            return f"{subj} has an absolute magnitude of {obj}"
        if p == "formername":
            return f"{subj} was formerly known as {obj}"
        if p == "birthdate":
            return f"{subj} was born on {obj}"
        if p == "deathdate":
            return f"{subj} died on {obj}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "deathcause":
            return f"{subj} died of {obj}"
        if p == "nationality" or p == "stateoforigin":
            return f"{subj} is from {obj}"
        if p == "almamater":
            return f"{subj} studied at {obj}"
        if p == "doctoralstudent":
            return f"{subj} supervised {obj}"
        # Fallback generic wording - use "has" for unknown predicates
        return f"{subj} has {pred} of {obj}"

    # Build clauses, trying to combine related information
    # First, collect all triples by subject
    subject_triples: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Find the main subject (the one with most triples or first in list)
    main_subject = triples[0].subject if triples else None
    if not main_subject:
        return ""

    # Get all triples for the main subject
    main_triples = subject_triples.get(main_subject, triples)

    # Build property phrases without repeating the subject
    property_phrases = []
    for t in main_triples:
        subj, pred, obj = t.subject, t.predicate, t.object
        p = pred.strip().lower()

        # Mapping of predicate to readable property phrase (without subject)
        if p == "discoverer":
            property_phrases.append(f"discovered by {obj}")
        elif p == "discovered":
            property_phrases.append(f"discovered on {obj}")
        elif p == "epoch":
            property_phrases.append(f"epoch {obj}")
        elif p == "apoapsis":
            property_phrases.append(f"apoapsis of {obj}")
        elif p == "periapsis":
            property_phrases.append(f"periapsis of {obj}")
        elif p == "orbitalperiod":
            property_phrases.append(f"orbital period of {obj}")
        elif p == "averagespeed":
            property_phrases.append(f"average speed of {obj}")
        elif p == "escapevelocity":
            property_phrases.append(f"escape velocity of {obj}")
        elif p == "mass":
            property_phrases.append(f"mass of {obj}")
        elif p == "density":
            property_phrases.append(f"density of {obj}")
        elif p == "temperature":
            property_phrases.append(f"temperature of {obj}")
        elif p == "maximumtemperature":
            property_phrases.append(f"maximum temperature of {obj}")
        elif p == "meantemperature":
            property_phrases.append(f"mean temperature of {obj}")
        elif p == "minimumtemperature":
            property_phrases.append(f"minimum temperature of {obj}")
        elif p == "rotationperiod":
            property_phrases.append(f"rotation period of {obj}")
        elif p == "surfacearea":
            property_phrases.append(f"surface area of {obj}")
        elif p == "absolutemagnitude":
            property_phrases.append(f"absolute magnitude of {obj}")
        elif p == "formername":
            property_phrases.append(f"formerly known as {obj}")
        elif p == "birthdate":
            property_phrases.append(f"born on {obj}")
        elif p == "deathdate":
            property_phrases.append(f"died on {obj}")
        elif p == "birthplace":
            property_phrases.append(f"born in {obj}")
        elif p == "deathplace":
            property_phrases.append(f"died in {obj}")
        elif p == "deathcause":
            property_phrases.append(f"died of {obj}")
        elif p == "nationality" or p == "stateoforigin":
            property_phrases.append(f"from {obj}")
        elif p == "almamater":
            property_phrases.append(f"studied at {obj}")
        elif p == "doctoralstudent":
            property_phrases.append(f"supervised {obj}")
        else:
            property_phrases.append(f"has {pred} of {obj}")

    # Build the sentence by combining all properties
    if len(property_phrases) == 1:
        sentence = f"{main_subject} {property_phrases[0]}."
    else:
        # Join properties with commas, using "and" before the last one
        all_but_last = property_phrases[:-1]
        last = property_phrases[-1]

        if len(all_but_last) == 1:
            sentence = f"{main_subject} {all_but_last[0]} and {last}."
        else:
            sentence = f"{main_subject} {', '.join(all_but_last)} and {last}."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

